import { Col, Form, Row, Select } from "antd"
import { useSelector } from "react-redux"
import InputCustom from "src/components/Input/InputCustom"
import SelectCustom from "src/components/Select/SelectCustom"
import { GUIDE_EMPTY, SYSTEM_KEY } from "src/constants/constants"
import { getListComboByKey } from "src/lib/utils"
import { SearchStyled } from "../styled"
import TreeSelectCustom from "src/components/Select/TreeSelectCustom"
import { removeDiacritics } from "src/lib/stringsUtils"
import { useEffect, useState } from "react"
import AssociationService from "src/services/AssociationService"
import { sort } from "../../Association/ListAssociation/ListAssociation"

const { Option } = Select
const Search = ({
  setStatus,
  getAllUser,
  setTextSearch,
  status,
  setSelectAssociation,
}) => {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [treeData, setTreeData] = useState([])
  const [loading, setLoading] = useState(false)

  const nest = (items, id, link) => {
    return items
      ?.filter(item => item[link] === id)
      .map(item => ({
        ...item,
        title: item.title,
        key: item.key,
        value: item.key,
        children: nest(items, item?.key, link),
      }))
  }

  const getListAssoc = async () => {
    try {
      setLoading(true)
      const res = await AssociationService.getAssociationNameList({
        AssociationID: GUIDE_EMPTY,
        AssociationName: "",
      })
      if (res?.isError) return
      const dataList = sort(
        res?.Object?.map(item => ({
          ...item,
          key: item?.AssociationID,
          title: item?.AssociationName || "",
          removeDiacriticsTitle: removeDiacritics(
            item?.AssociationName.toLowerCase(),
          ),
        })),
      )

      const tree = nest(sort(dataList), GUIDE_EMPTY, "ParentID")

      setTreeData({ tree: tree, dataList: dataList })
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    getListAssoc()
  }, [])

  return (
    <SearchStyled>
      <Row gutter={[16, 16]}>
        {/* <Col span={8}>
          <Form.Item
            name="ParentId"
            rules={[
              {
                required: true,
                message: "Thông tin không được để trống",
              },
            ]}
          >
            <TreeSelectCustom
              showSearch
              style={{ width: "100%" }}
              styles={{
                popup: { root: { maxHeight: 400, overflow: "auto" } },
              }}
              placeholder="Chọn hội"
              allowClear
              treeDefaultExpandAll
              treeData={treeData?.tree}
              filterTreeNode={(input, treeNode) => {
                const title = removeDiacritics(treeNode.title.toLowerCase())
                const searchValue = removeDiacritics(input.toLowerCase())
                return title.indexOf(searchValue) !== -1
              }}
              onChange={value => {
                setSelectAssociation(value)
              }}
            />
          </Form.Item>
        </Col> */}
        <Col flex="auto">
          <InputCustom
            onChange={e => setTextSearch(e?.target?.value)}
            onSearch={getAllUser}
            type="search"
            allowClear
            label="Nhập tên tài khoản, số điện thoại, email"
          />
        </Col>
        <Col lg={5} xs={24}>
          <SelectCustom
            label="Trạng thái"
            onChange={Status => {
              setStatus(Status)
            }}
            value={status}
          >
            {getListComboByKey(SYSTEM_KEY?.COMMON_STATUS, listSystemKey)?.map(
              i => (
                <Option key={+i.CodeValue} value={+i.CodeValue}>
                  {i?.Description}
                </Option>
              ),
            )}
          </SelectCustom>
        </Col>
      </Row>
    </SearchStyled>
  )
}

export default Search
