import { Spin, Tree } from "antd"
import { useEffect, useState } from "react"
import CB1 from "src/components/Modal/CB1"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import Notice from "src/components/Notice"
import { GUIDE_EMPTY } from "src/constants/constants"
import { convertTreeData } from "src/lib/utils"
import DepartmentService from "src/services/DepartmentService"
import ModalAddDept from "../modal/ModalAddDept"
import { TreeAnchorStyled } from "../styled"

const TreeAnchor = ({
  keyId,
  selectedNode,
  setSelectedNote,
  getAllUser,
  // selectAssociation,
}) => {
  const [loading, setLoading] = useState(false)
  const [listDept, setListDept] = useState()
  const [isOpenModal, setIsOpenModal] = useState(false)
  const [isEdit, setIsEdit] = useState(false)
  const [dataInfo, setDataInfo] = useState(undefined)
  const [button, setButton] = useState()

  useEffect(() => {
    getListDepartment()
  }, [])

  const getListDepartment = async () => {
    try {
      setLoading(true)
      const res = await DepartmentService.getListDept({ departmentName: "" })
      const tree = convertTreeData([...res.Object.data], true)
      setListDept(tree)
      setSelectedNote(e => (!e ? tree[0] : e))
      setButton(res?.Object?.buttonShow)
    } finally {
      setLoading(false)
    }
  }

  // const getListDepartment = async () => {
  //   try {
  //     setLoading(true)
  //     const res = await DepartmentService.getListDept({ departmentName: "" })

  //     // Lọc dữ liệu theo AssociationID
  //     const filteredData = res.Object.data.filter(
  //       item => item.AssociationID === selectAssociation,
  //     )

  //     const tree = convertTreeData([...filteredData], true)
  //     setListDept(tree)
  //     setSelectedNote(e => (!e ? tree[0] : e))
  //     setButton(res?.Object?.buttonShow)
  //   } finally {
  //     setLoading(false)
  //   }
  // }

  const ACTION = [
    {
      visible: button?.IsInsertUpdate,
      icon: "add-blue",
      title: "Thêm phòng ban",
      onClick: nodeData => {
        setIsOpenModal(true)
        setDataInfo(nodeData)
      },
    },
    {
      visible: button?.IsInsertUpdate,
      icon: "edit",
      title: "Sửa thông tin",
      onClick: nodeData => {
        setIsOpenModal(true)
        setDataInfo(nodeData)
        setIsEdit(true)
      },
    },
    {
      visible: button?.IsDelete,
      icon: "deleteRow",
      title: "Xóa phòng ban",
      onClick: nodeData => {
        CB1({
          title: `Bạn có chắc chắn muốn xoá phòng ban
          ${nodeData?.DepartmentName} không? 
          Nhân viên trong phòng ban này sẽ bị xóa kèm theo phòng ban!!!`,
          icon: "warning-usb",
          okText: "Đồng ý",
          onOk: async close => {
            setLoading(true)
            DepartmentService.deleteDept({
              DepartmentId: nodeData.DepartmentID,
            })
              .then(res => {
                if (res.isOk) {
                  Notice({
                    msg: "Thành công",
                    isSuccess: true,
                  })
                  getListDepartment()
                  getAllUser()
                }
              })
              .finally(() => {
                setLoading(false)
              })
            close()
          },
        })
      },
    },
  ]

  useEffect(() => {
    getListDepartment()
  }, [])

  return (
    <TreeAnchorStyled>
      <Spin spinning={loading}>
        <div className="div-all">
          <div className="fs-16 fw-600 mt-0 mb-10">Danh sách phòng ban</div>
          {button?.IsInsertUpdate && (
            <div className="float-action__wrapper">
              <ButtonCircle
                style={{ margin: "0 5px" }}
                title={"Thêm phòng ban"}
                key={"add-blue"}
                iconName={"add-blue"}
                onClick={() => {
                  setIsOpenModal(true)
                  setDataInfo({
                    DepartmentName: "Công đoàn Y tế Việt Nam",
                    DepartmentID: GUIDE_EMPTY,
                  })
                }}
              />
            </div>
          )}
        </div>
        {!!listDept?.length && (
          <Tree
            defaultExpandAll
            treeData={listDept}
            selectedKeys={[selectedNode?.key]}
            onSelect={(_, e) => setSelectedNote(e?.node)}
            titleRender={(nodeData, idx) => {
              return (
                <div key={idx + 1} className="d-flex align-items-center">
                  {nodeData.title}
                  {keyId > 0 && (
                    <div className="list-button">
                      {ACTION?.filter(i => !!i?.visible).map(value => (
                        <ButtonCircle
                          style={{ margin: "0 5px" }}
                          title={value.title}
                          key={value.icon}
                          iconName={value.icon}
                          onClick={() => {
                            value.onClick(nodeData)
                          }}
                        />
                      ))}
                    </div>
                  )}
                </div>
              )
            }}
          />
        )}
      </Spin>
      {isOpenModal && (
        <ModalAddDept
          isEdit={isEdit}
          visible={isOpenModal}
          dataInfo={dataInfo}
          onCancel={() => {
            setIsOpenModal(false)
            setDataInfo(undefined)
            setIsEdit(false)
          }}
          onOk={() => {
            getListDepartment()
            getAllUser()
          }}
        />
      )}
    </TreeAnchorStyled>
  )
}

export default TreeAnchor
